from kafka import AdminClient
from kafka.errors import TopicAlreadyExistsError
import argparse

parser = argparse.ArgumentParser(description='Kafka Topic Management')
parser.add_argument('--topic', required=True, help='Topic name')
parser.add_argument('--partitions', type=int, default=1, help='Number of partitions')
parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor')
parser.add_argument('--config', nargs='*', help='Topic configuration key-value pairs')

args = parser.parse_args()

admin_client = AdminClient({'bootstrap.servers': 'kafka-brokers:9092'})

try:
    topic_config = {
        'partitions': args.partitions,
        'replication_factor': args.replication_factor,
        **{key: value for key, value in [pair.split('=') for pair in args.config]}
    }
    admin_client.create_topic(name=args.topic, config=topic_config)
    print(f'Topic {args.topic} created.')
except TopicAlreadyExistsError:
    print(f'Topic {args.topic} already exists.')